svg.script:
(function(){
  var t=document.getElementById('toggle-terminals');
  if(t) t.addEventListener('change',function(e){
    var show=e.target.checked;
    var ns=document.querySelectorAll('.terminal-node');
    var es=document.querySelectorAll('.terminal-edge');
    for(var i=0;i<ns.length;i++) ns[i].style.display=show?'':'none';
    for(var i=0;i<es.length;i++) es[i].style.display=show?'':'none';
  });
})();
